(function(){"use strict";var t=document.getElementById("year");if(t&&(t.textContent=new Date().getFullYear()),"IntersectionObserver"in window){var r=new IntersectionObserver(function(e){e.forEach(function(n){n.isIntersecting&&n.target.classList.add("visible")})},{threshold:.1,rootMargin:"0px 0px -50px 0px"});document.querySelectorAll(".reveal").forEach(function(e){r.observe(e)})}})();
